152	/** Returns a paginated slice of eval runs (newest first) using LIMIT/OFFSET at the DB level. */
153	export function getRunsPage(page: number, pageSize: number): RunsPage {
154	  const db = getDb();
155	  const countRow = db.query("SELECT COUNT(*) as count FROM eval_runs").get() as { count: number };
156	  const total = countRow.count;
157	  const totalPages = total === 0 ? 1 : Math.ceil(total / pageSize);
158	  const safePage = Math.max(1, Math.min(page, totalPages));
159	  const offset = (safePage - 1) * pageSize;
160	  const runs = db.query(
161	    "SELECT * FROM eval_runs ORDER BY timestamp DESC LIMIT ? OFFSET ?"
162	  ).all(pageSize, offset) as EvalRun[];
163	  return { runs, total, page: safePage, totalPages };
164	}
