171	export function getRunResults(runId: string, agent?: string, score?: string): EvalResult[] {
172	  const db = getDb();
173	  let sql = "SELECT * FROM eval_results WHERE run_id = ?";
174	  const params: unknown[] = [runId];
175	  if (agent) { sql += " AND agent = ?"; params.push(agent); }
176	  if (score) { sql += " AND score = ?"; params.push(score); }
177	  sql += " ORDER BY agent, scenario_id, trial_index";
178	  return db.query(sql).all(...params) as EvalResult[];
179	}
